func taskVals(task tasks.Task) string {
	completed := "true"
	if task.Completed {
		completed = "false"
	}
	vals := map[string]string{"completed": completed}
	if task.ListTitle != "" {
		vals["listTitle"] = task.ListTitle
	}
	b, _ := json.Marshal(vals)
	return string(b)
}

func listTitleQS(listTitle string) string {
	if listTitle == "" {
		return ""
	}
	return "?listTitle=" + url.QueryEscape(listTitle)
}

func toggleChildren(taskID string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_toggleChildren_42bd`,
		Function: `function __templ_toggleChildren_42bd(taskID){const el = document.getElementById('children-' + taskID);
	if (!el) return;
	const btn = document.querySelector('[data-toggle-id="' + taskID + '"] svg');
	if (el.style.display === 'none') {
		el.style.display = '';
		if (btn) btn.style.transform = '';
	} else {
		el.style.display = 'none';
		if (btn) btn.style.transform = 'rotate(-90deg)';
	}
}`,
		Call:       templ.SafeScript(`__templ_toggleChildren_42bd`, taskID),
		CallInline: templ.SafeScriptInline(`__templ_toggleChildren_42bd`, taskID),
	}
}

func formatDue(due string) string {
	t, err := time.Parse("2006-01-02", due)
	if err != nil {
		return due
	}
	now := time.Now()
	if t.Year() == now.Year() {
		return t.Format("Jan 2")
	}
	return t.Format("Jan 2, 2006")
}

func dueDateClass(due string, completed bool) string {
	if completed {
		return "text-gray-400 dark:text-gray-500"
	}
	t, err := time.Parse("2006-01-02", due)
	if err != nil {
		return "text-gray-400 dark:text-gray-500"
	}
	today := time.Now().Format("2006-01-02")
	todayT, _ := time.Parse("2006-01-02", today)
	if t.Before(todayT) {
		return "text-red-500 dark:text-red-400"
	}
	if t.Equal(todayT) {
		return "text-amber-500 dark:text-amber-400"
	}
	return "text-gray-400 dark:text-gray-500"
}

func showSubtaskInput(taskID string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_showSubtaskInput_2abf`,
		Function: `function __templ_showSubtaskInput_2abf(taskID){const form = document.getElementById('subtask-form-' + taskID);
	if (!form) return;
	// Ensure children container is visible
	const children = document.getElementById('children-' + taskID);
	if (children) children.style.display = '';
	const btn = document.querySelector('[data-toggle-id="' + taskID + '"] svg');
	if (btn) btn.style.transform = '';
	form.style.display = '';
	form.querySelector('input[name=title]').focus();
}`,
		Call:       templ.SafeScript(`__templ_showSubtaskInput_2abf`, taskID),
		CallInline: templ.SafeScriptInline(`__templ_showSubtaskInput_2abf`, taskID),
	}
}

